import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as e,e as g}from"./app-405c8987.js";const t="/assets/image-20240502144919070-300ff4d3.png",n="/assets/image-20240502144950226-da10f8bc.png",r="/assets/image-20240502145105896-6dde0dec.png",s="/assets/image-20240502145143945-fe163cce.png",c="/assets/image-20240502145227976-085ade2f.png",p="/assets/image-20240502145255442-e43ade85.png",o="/assets/image-20240502145330903-dccc70b1.png",d="/assets/image-20240502145423870-17cad6cf.png",m="/assets/image-20240502145515183-4b126e98.png",f="/assets/image-20240502145620696-aeb2a5cb.png",h="/assets/image-20240502145811361-b6333888.png",l="/assets/image-20240502145847014-dea8d26d.png",u="/assets/image-20240502150037933-c92c8e8f.png",_="/assets/image-20240502150148562-ae4d3331.png",b="/assets/image-20240502150343878-be9828ae.png",x="/assets/image-20240502150505314-4f6046b9.png",y="/assets/image-20240502150712476-3b6a9395.png",z="/assets/image-20240502150758539-078eceb4.png",A="/assets/image-20240502150827692-774f7218.png",M="/assets/image-20240502150918040-729d479a.png",T="/assets/image-20240502151022073-aea2b61b.png",k="/assets/image-20240502151100321-a57e3040.png",v={},B=g('<h1 id="mat博主教程" tabindex="-1"><a class="header-anchor" href="#mat博主教程" aria-hidden="true">#</a> MAT博主教程</h1><h2 id="精通支撑位-阻力位交易策略" tabindex="-1"><a class="header-anchor" href="#精通支撑位-阻力位交易策略" aria-hidden="true">#</a> 精通支撑位&amp;阻力位交易策略</h2><p>这只影片我将会介绍：</p><p>1、什么是支撑线和阻力线</p><p>2、4个使用支撑与阻力线必须知道的事</p><p>3、使用支撑与阻力线来进场和出场的交易策略</p><p>4、最后我将会分享我如何画支撑与阻力线的技巧与细节。</p><h3 id="什么是阻力线" tabindex="-1"><a class="header-anchor" href="#什么是阻力线" aria-hidden="true">#</a> 什么是阻力线？</h3><p>阻力线是当股价多次突破不了某个价位，那个位置就形成股价的阻力位，在画阻力线时至少连接两个或以上的点方为一个有效的阻力。</p><figure><img src="'+t+'" alt="image-20240502144919070" tabindex="0" loading="lazy"><figcaption>image-20240502144919070</figcaption></figure><h3 id="什么是支撑线" tabindex="-1"><a class="header-anchor" href="#什么是支撑线" aria-hidden="true">#</a> 什么是支撑线？</h3><p>支撑线是当股价多次跌不破某个位置，那个位置就形成一个支撑。一个有效的支撑线是至少连接两个或以上的点。</p><figure><img src="'+n+'" alt="image-20240502144950226" tabindex="0" loading="lazy"><figcaption>image-20240502144950226</figcaption></figure><h3 id="支撑与阻力的知识与细节" tabindex="-1"><a class="header-anchor" href="#支撑与阻力的知识与细节" aria-hidden="true">#</a> 支撑与阻力的知识与细节</h3><h4 id="支撑与阻力线的转化运用" tabindex="-1"><a class="header-anchor" href="#支撑与阻力线的转化运用" aria-hidden="true">#</a> 支撑与阻力线的转化运用</h4><p>当股价突破阻力线时，阻力线将会变成支撑线，当下次市股价回到该位置时就会形成支撑，支撑住股价。</p><figure><img src="'+r+'" alt="image-20240502145105896" tabindex="0" loading="lazy"><figcaption>image-20240502145105896</figcaption></figure><p>反之当股价跌破支撑线时，支撑线将会变成阻力线，当股价再次回到该价位，它将形成有效的阻力。</p><figure><img src="'+s+'" alt="image-20240502145143945" tabindex="0" loading="lazy"><figcaption>image-20240502145143945</figcaption></figure><h4 id="支撑与阻力的强度与有效性" tabindex="-1"><a class="header-anchor" href="#支撑与阻力的强度与有效性" aria-hidden="true">#</a> 支撑与阻力的强度与有效性</h4><p>当一个支撑与阻力线连接越多的点，它的强度以及有效的程度越大。所以举个例子，一个连接了4个点的阻力线，会比连接两个点的阻力线来的有效。</p><figure><img src="'+c+'" alt="image-20240502145227976" tabindex="0" loading="lazy"><figcaption>image-20240502145227976</figcaption></figure><figure><img src="'+p+'" alt="image-20240502145255442" tabindex="0" loading="lazy"><figcaption>image-20240502145255442</figcaption></figure><h4 id="区域对待" tabindex="-1"><a class="header-anchor" href="#区域对待" aria-hidden="true">#</a> 区域对待</h4><p>支撑与阻力并不是单单一条线，我们要把它当做一个区域来对待。所以当股价到达支撑区域或阻力区域就会有所反弹。</p><figure><img src="'+o+'" alt="image-20240502145330903" tabindex="0" loading="lazy"><figcaption>image-20240502145330903</figcaption></figure><figure><img src="'+d+'" alt="image-20240502145423870" tabindex="0" loading="lazy"><figcaption>image-20240502145423870</figcaption></figure><p>当你实际画的时候，是不是觉得很混乱，觉得太多支撑与阻力线了。分不清楚要使用哪一个。</p><figure><img src="'+m+'" alt="image-20240502145515183" tabindex="0" loading="lazy"><figcaption>image-20240502145515183</figcaption></figure><h4 id="不同时间级别的支撑与阻力" tabindex="-1"><a class="header-anchor" href="#不同时间级别的支撑与阻力" aria-hidden="true">#</a> 不同时间级别的支撑与阻力</h4><p>从大时间级别来化，支撑与阻力会比较清晰以及简单。以及大时间级别的支撑与阻力会比小时间级别的支撑与阻力强度与有效度来得大。所以在使用大时间级别的图画支撑与阻力时，你就会很清楚地发现重要的支撑与阻力不会再画几十条支撑与阻力了。</p><figure><img src="'+f+'" alt="image-20240502145620696" tabindex="0" loading="lazy"><figcaption>image-20240502145620696</figcaption></figure><h3 id="进场的策略" tabindex="-1"><a class="header-anchor" href="#进场的策略" aria-hidden="true">#</a> 进场的策略</h3><p>首先进场的策略分别是突破买入法和回调买入，我会分别介绍以及他们的优缺点。</p><h4 id="突破买入法" tabindex="-1"><a class="header-anchor" href="#突破买入法" aria-hidden="true">#</a> 突破买入法</h4><p>突破买入是当股价突破阻力线时，我们可以看作是突破了某个重要的障碍，接下来看涨。</p><figure><img src="'+h+'" alt="image-20240502145811361" tabindex="0" loading="lazy"><figcaption>image-20240502145811361</figcaption></figure><p>所以当股价突破阻力位置时就可以买入，优点是可以及时捉到后面一大波的利润。缺点是如果有假突破，你将会买在高点住在高楼，什么是假突破呢？我之后会做关于假突破的视频来讲解。</p><figure><img src="'+l+'" alt="image-20240502145847014" tabindex="0" loading="lazy"><figcaption>image-20240502145847014</figcaption></figure><h4 id="回调买入法" tabindex="-1"><a class="header-anchor" href="#回调买入法" aria-hidden="true">#</a> 回调买入法</h4><p>回调买入法是当股价突破阻力时，等待股价再次回落，该位置才进行买入。动作优点是比较稳健和安全，缺点是股价没有进行回调，而是直接暴涨，那你将会错失一大波的涨幅，错失机会。</p><figure><img src="'+u+'" alt="image-20240502150037933" tabindex="0" loading="lazy"><figcaption>image-20240502150037933</figcaption></figure><h3 id="离场的策略" tabindex="-1"><a class="header-anchor" href="#离场的策略" aria-hidden="true">#</a> 离场的策略</h3><p>离场的策略是我们可以使用支撑线来设置止损。我们可以把止损点设置在支撑位的下方，所以股价要抵达你的止损点之前必须要挑战了支撑位方才可以触碰到你的止损。</p><figure><img src="'+_+'" alt="image-20240502150148562" tabindex="0" loading="lazy"><figcaption>image-20240502150148562</figcaption></figure><h3 id="画支撑与阻力线的细节与心得" tabindex="-1"><a class="header-anchor" href="#画支撑与阻力线的细节与心得" aria-hidden="true">#</a> 画支撑与阻力线的细节与心得</h3><p>线是要画在实体上还是虚线上？</p><p>我的画法是以触碰到最多点的大前提下，无论是触碰到实体或者是虚线上。首先我会去大时间级别的图来画支撑与阻力，因为我是波段交易者，所以我的大时间级别是周图和月图，日图是我的小时间级别。</p><figure><img src="'+b+'" alt="image-20240502150343878" tabindex="0" loading="lazy"><figcaption>image-20240502150343878</figcaption></figure><p>我通常指绘画靠近现在的股价的支撑与阻力，这样会节省很多时间，之后股价突破或跌破后再画就是了。我的做法是先画了一条线，再把它画成一个区域，然后颜色改成青色，以此区别大时间级别和小时间级别的支撑与阻力。画完月图和周图后，我就会转去日图画股价最近的支撑与阻力。所以这样就很清楚了，以DENX这支股为例子，阻力是0.83，支撑是0.78。</p><figure><img src="'+x+'" alt="image-20240502150505314" tabindex="0" loading="lazy"><figcaption>image-20240502150505314</figcaption></figure><h3 id="完整策略示范" tabindex="-1"><a class="header-anchor" href="#完整策略示范" aria-hidden="true">#</a> 完整策略示范</h3><p>画支撑线，画阻力线</p><figure><img src="'+y+'" alt="image-20240502150712476" tabindex="0" loading="lazy"><figcaption>image-20240502150712476</figcaption></figure><p>在支撑位下方设置止损点，在阻力位设置止盈点</p><figure><img src="'+z+'" alt="image-20240502150758539" tabindex="0" loading="lazy"><figcaption>image-20240502150758539</figcaption></figure><p>等待</p><figure><img src="'+A+'" alt="image-20240502150827692" tabindex="0" loading="lazy"><figcaption>image-20240502150827692</figcaption></figure><p>突破买入</p><figure><img src="'+M+'" alt="image-20240502150918040" tabindex="0" loading="lazy"><figcaption>image-20240502150918040</figcaption></figure><p>在支撑位下方设置止损点</p><figure><img src="'+T+'" alt="image-20240502151022073" tabindex="0" loading="lazy"><figcaption>image-20240502151022073</figcaption></figure><figure><img src="'+k+'" alt="image-20240502151100321" tabindex="0" loading="lazy"><figcaption>image-20240502151100321</figcaption></figure><p>支撑与阻力是技术分析的必学的技巧，但我们并不能单单用支撑与阻力来当作唯一的买点，需配合其他的技术面工具及分析。</p>',64),E=[B];function N(D,S){return i(),e("div",null,E)}const j=a(v,[["render",N],["__file","MTA博主教程.html.vue"]]);export{j as default};
